# Student Analytics - Fix Pages Script
# Run this from the student-analytics folder: .\fix-pages.ps1

Write-Host "Creating page folders and files..." -ForegroundColor Cyan

# --- frontend/src/app/pages/login/login.component.ts ---
New-Item -ItemType Directory -Force -Path "frontend\src\app\pages\login" | Out-Null
$b64 = ""
[System.IO.File]::WriteAllBytes("frontend\src\app\pages\login\login.component.ts", [System.Convert]::FromBase64String($b64))
Write-Host "  Created: frontend/src/app/pages/login/login.component.ts" -ForegroundColor Green

